  const specDir = path.join(SPECS_DIR, slug);
  const proc = spawn('bash', ['-c', `git add "${specDir}" && git commit -m "${message}" && git push`], {
    cwd: PROJECT_ROOT,
    stdio: ['ignore', 'pipe', 'pipe'],
