262	function deriveStatus(slug: string): string {
263	  const r = running.get(slug);
264	  if (r) return 'running-' + r.step;
265	
266	  // Check for dispatch running
267	  if (running.has(slug + ':dispatch')) return 'dispatching';
268	
269	  const dir = path.join(SPECS_DIR, slug);
270	  const has = (f: string) => fs.existsSync(path.join(dir, f));
271	
272	  // If we have a writ ID, check its status for post-dispatch states
273	  const meta = readMeta(slug);
274	  if (meta.writId) {
275	    const writ = getWritSync(meta.writId);
276	    if (writ) {
277	      if (writ.status === 'completed') return 'complete';
278	      if (writ.status === 'failed') return 'failed';
279	      if (writ.status === 'active') return 'implementing';
280	      if (writ.status === 'ready') return 'dispatched';
281	      if (writ.status === 'cancelled') return 'cancelled';
282	    }
283	  }
284	
285	  if (has('spec.md')) return 'spec';
