'    html += \'<span id="link-writ-status" class="link-status"></span>\';\n' +
'    html += \'<datalist id="link-writs"></datalist>\';\n' +
'    html += \'</div>\';\n' +
'    html += \'</div>\';\n' +
'\n' +
'    if (specs.length === 0) {\n' +
